solve(S, K) ->
    Result = process_string(S, []),
    case K >= 0 andalso K < length(Result) of
        true -> [Char] = lists:sublist(Result, K+1, 1),
                <<Char>>;
        false -> <<".">>
    end.

process_string([], Acc) -> Acc;
process_string([H | T], Acc) ->
    case H of
        $* -> NewAcc = case Acc of
                         [] -> [];
                         [_ | Rest] -> Rest
                       end,
              process_string(T, NewAcc);
        $# -> NewAcc = Acc ++ Acc,
              process_string(T, NewAcc);
        $% -> NewAcc = lists:reverse(Acc),
              process_string(T, NewAcc);
        _ when H >= $a, H =< $z -> NewAcc = Acc ++ [H],
                                    process_string(T, NewAcc);
        _ -> process_string(T, Acc)
    end.
